DO $$
BEGIN
  CREATE TYPE public.app_role AS ENUM ('admin', 'user', 'staff');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;
DO $$
BEGIN
  CREATE TYPE public.order_status AS ENUM ('pending', 'confirmed', 'shipped', 'delivered', 'cancelled', 'incomplete', 'processing', 'on_the_way', 'on_hold', 'in_courier', 'completed');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

CREATE TABLE IF NOT EXISTS public.profiles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL UNIQUE, email text, display_name text, avatar_url text, phone text, address text, city text, postal_code text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_roles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, role public.app_role NOT NULL DEFAULT 'user', created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(user_id, role));
CREATE TABLE IF NOT EXISTS public.permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), menu_key text NOT NULL UNIQUE, label text NOT NULL, description text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.role_permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), role public.app_role NOT NULL, permission_id uuid NOT NULL REFERENCES public.permissions(id) ON DELETE CASCADE, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(role, permission_id));

CREATE OR REPLACE FUNCTION public.has_role(_user_id uuid, _role public.app_role) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = _user_id AND role = _role) $$;
CREATE OR REPLACE FUNCTION public.update_updated_at_column() RETURNS trigger LANGUAGE plpgsql SET search_path TO 'public' AS $$ BEGIN NEW.updated_at = now(); RETURN NEW; END; $$;
CREATE OR REPLACE FUNCTION public.get_user_menu_keys(_user_id uuid) RETURNS TABLE(menu_key text) LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT DISTINCT p.menu_key FROM public.user_roles ur JOIN public.role_permissions rp ON rp.role = ur.role JOIN public.permissions p ON p.id = rp.permission_id WHERE ur.user_id = _user_id AND p.menu_key IS NOT NULL $$;
CREATE OR REPLACE FUNCTION public.current_user_is_admin() RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT public.has_role(auth.uid(), 'admin'::public.app_role) $$;
CREATE OR REPLACE FUNCTION public.admin_exists() RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE role = 'admin') $$;
CREATE OR REPLACE FUNCTION public.promote_first_admin() RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF EXISTS (SELECT 1 FROM public.user_roles WHERE role = 'admin') THEN RETURN public.has_role(auth.uid(), 'admin'::public.app_role); END IF; IF auth.uid() IS NULL THEN RETURN false; END IF; INSERT INTO public.user_roles (user_id, role) VALUES (auth.uid(), 'admin') ON CONFLICT (user_id, role) DO NOTHING; RETURN true; END; $$;

CREATE TABLE IF NOT EXISTS public.site_settings (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), site_name text DEFAULT 'Navigator Series Book', logo_url text, favicon_url text, hero_title text, hero_subtitle text, contact_email text, contact_phone text, whatsapp_number text, address text, currency text DEFAULT 'BDT', home_reviews_enabled boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.social_links (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), platform text NOT NULL, url text NOT NULL, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE, description text, image_url text, is_active boolean DEFAULT true, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.subcategories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), category_id uuid REFERENCES public.categories(id) ON DELETE CASCADE, name text NOT NULL, slug text UNIQUE, image_url text, is_active boolean DEFAULT true, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.childcategories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), subcategory_id uuid REFERENCES public.subcategories(id) ON DELETE CASCADE, name text NOT NULL, slug text UNIQUE, image_url text, is_active boolean DEFAULT true, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.brands (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE, logo_url text, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.colors (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, value text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.sizes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.models (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.products (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE, description text, short_description text, price numeric NOT NULL DEFAULT 0, sale_price numeric, compare_at_price numeric, cost_price numeric, sku text, stock_quantity integer DEFAULT 0, image_url text, images text[], gallery_urls text[], category_id uuid REFERENCES public.categories(id) ON DELETE SET NULL, subcategory_id uuid REFERENCES public.subcategories(id) ON DELETE SET NULL, childcategory_id uuid REFERENCES public.childcategories(id) ON DELETE SET NULL, brand_id uuid REFERENCES public.brands(id) ON DELETE SET NULL, is_active boolean DEFAULT true, is_featured boolean DEFAULT false, weight numeric, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.product_colors (product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, color_id uuid REFERENCES public.colors(id) ON DELETE CASCADE, PRIMARY KEY(product_id, color_id));
CREATE TABLE IF NOT EXISTS public.product_sizes (product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, size_id uuid REFERENCES public.sizes(id) ON DELETE CASCADE, PRIMARY KEY(product_id, size_id));
CREATE TABLE IF NOT EXISTS public.product_models (product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, model_id uuid REFERENCES public.models(id) ON DELETE CASCADE, PRIMARY KEY(product_id, model_id));
CREATE TABLE IF NOT EXISTS public.product_variants (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE, color_id uuid REFERENCES public.colors(id) ON DELETE SET NULL, size_id uuid REFERENCES public.sizes(id) ON DELETE SET NULL, model_id uuid REFERENCES public.models(id) ON DELETE SET NULL, sku text, price numeric, stock_quantity integer DEFAULT 0, image_url text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.banner_categories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, slug text UNIQUE, sort_order integer DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.banners (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title text, subtitle text, image_url text NOT NULL, link_url text, banner_category_id uuid REFERENCES public.banner_categories(id) ON DELETE SET NULL, sort_order integer DEFAULT 0, is_active boolean DEFAULT true, starts_at timestamptz, ends_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.pages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title text NOT NULL, slug text NOT NULL UNIQUE, content text, is_published boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.payment_methods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, type text DEFAULT 'manual', instructions text, account_number text, is_active boolean DEFAULT true, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.shipping_charges (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, amount numeric NOT NULL DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.product_shipping_charges (product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, shipping_charge_id uuid REFERENCES public.shipping_charges(id) ON DELETE CASCADE, PRIMARY KEY(product_id, shipping_charge_id));
CREATE TABLE IF NOT EXISTS public.variant_shipping_charges (variant_id uuid REFERENCES public.product_variants(id) ON DELETE CASCADE, shipping_charge_id uuid REFERENCES public.shipping_charges(id) ON DELETE CASCADE, PRIMARY KEY(variant_id, shipping_charge_id));
CREATE TABLE IF NOT EXISTS public.shipping_zones (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, charge numeric NOT NULL DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.districts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, division text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.thanas (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), district_id uuid REFERENCES public.districts(id) ON DELETE CASCADE, name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.shipping_zone_districts (shipping_zone_id uuid REFERENCES public.shipping_zones(id) ON DELETE CASCADE, district_id uuid REFERENCES public.districts(id) ON DELETE CASCADE, PRIMARY KEY(shipping_zone_id, district_id));
CREATE TABLE IF NOT EXISTS public.customers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid, name text NOT NULL, email text, phone text, address text, district text, thana text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.orders (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), invoice_no text UNIQUE DEFAULT ('INV-' || upper(substr(gen_random_uuid()::text, 1, 8))), customer_id uuid REFERENCES public.customers(id) ON DELETE SET NULL, customer_name text, email text, phone text, address text, district text, thana text, subtotal numeric DEFAULT 0, shipping_charge numeric DEFAULT 0, discount numeric DEFAULT 0, total numeric NOT NULL DEFAULT 0, status public.order_status DEFAULT 'pending', payment_method text, payment_status text DEFAULT 'pending', transaction_id text, notes text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.order_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_id uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE, product_id uuid REFERENCES public.products(id) ON DELETE SET NULL, product_name text NOT NULL, unit_price numeric NOT NULL DEFAULT 0, quantity integer NOT NULL DEFAULT 1, total numeric GENERATED ALWAYS AS (unit_price * quantity) STORED, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.order_statuses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, color text, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.pending_payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), customer_name text, phone text, address text, total numeric DEFAULT 0, payment_method text, transaction_id text, cart_items jsonb DEFAULT '[]'::jsonb, notes text, status text DEFAULT 'pending', created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.coupons (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text NOT NULL UNIQUE, type text DEFAULT 'fixed', value numeric NOT NULL DEFAULT 0, min_order_amount numeric DEFAULT 0, max_discount numeric, usage_limit integer, used_count integer DEFAULT 0, starts_at timestamptz, expires_at timestamptz, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.coupon_products (coupon_id uuid REFERENCES public.coupons(id) ON DELETE CASCADE, product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, PRIMARY KEY(coupon_id, product_id));
CREATE TABLE IF NOT EXISTS public.notifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), audience text NOT NULL DEFAULT 'admin', user_id uuid, type text, title text NOT NULL, message text, link text, meta jsonb DEFAULT '{}'::jsonb, is_read boolean DEFAULT false, read_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.contact_messages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, email text, phone text, subject text, message text NOT NULL, is_read boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.customer_messages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), customer_id uuid, sender text NOT NULL, body text NOT NULL, is_read boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.newsletter_subscribers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text NOT NULL UNIQUE, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.popups (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title text, content text, image_url text, link_url text, trigger_type text DEFAULT 'on_load', delay_seconds integer DEFAULT 0, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.pixels (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, provider text NOT NULL, pixel_id text, script text, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.landing_pages (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title text NOT NULL, slug text NOT NULL UNIQUE, content jsonb DEFAULT '{}'::jsonb, is_published boolean DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.price_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), product_id uuid REFERENCES public.products(id) ON DELETE CASCADE, old_price numeric, new_price numeric, changed_by uuid, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.courier_shipments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), order_id uuid REFERENCES public.orders(id) ON DELETE CASCADE, courier text NOT NULL, tracking_id text, status text, payload jsonb DEFAULT '{}'::jsonb, response jsonb DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.email_logs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), recipient text NOT NULL, subject text, status text, error text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.incomplete_orders (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), cart_items jsonb DEFAULT '[]'::jsonb, customer_info jsonb DEFAULT '{}'::jsonb, total numeric DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.manual_payment_methods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, account_number text, instructions text, is_active boolean DEFAULT true, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.home_reviews (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, rating integer DEFAULT 5, comment text, image_url text, is_active boolean DEFAULT true, sort_order integer DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.admin_password_otps (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text NOT NULL, code_hash text NOT NULL, expires_at timestamptz NOT NULL, used boolean NOT NULL DEFAULT false, attempts integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS public.user_password_otps (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), email text NOT NULL, code_hash text NOT NULL, expires_at timestamptz NOT NULL, used boolean NOT NULL DEFAULT false, attempts integer NOT NULL DEFAULT 0, created_at timestamptz NOT NULL DEFAULT now());


